import{_ as e,c as i,o as s,ae as t}from"./chunks/framework.B7Y1jjX-.js";const k=JSON.parse('{"title":"代码运行过程","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/浏览器与环境/JS底层.md","filePath":"generated-notes/前端/浏览器与环境/JS底层.md"}'),n={name:"generated-notes/前端/浏览器与环境/JS底层.md"};function o(l,a,r,d,h,c){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="代码运行过程" tabindex="-1">代码运行过程 <a class="header-anchor" href="#代码运行过程" aria-label="Permalink to &quot;代码运行过程&quot;">​</a></h1><p>源代码- &gt;解析器（parser）-&gt;AST-&gt;解释器（interperter）-&gt;字节码-&gt;编译器（TurboFan）-&gt;汇编 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020250903153123.png">查看图片：Pasted image 20250903153123.png</a></p><h5 id="parser生成抽象语法树" tabindex="-1">Parser生成抽象语法树 <a class="header-anchor" href="#parser生成抽象语法树" aria-label="Permalink to &quot;Parser生成抽象语法树&quot;">​</a></h5><p>在Chrome中开始下载Javascript文件后，Parser就会开始并行在单独的线程上解析代码。这意味着解析可以在下载完成后仅几毫秒内完成，并生成<a href="https://zhida.zhihu.com/search?content_id=109575458&amp;content_type=Article&amp;match_order=1&amp;q=AST&amp;zhida_source=entity" target="_blank" rel="noreferrer">AST</a>。 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020250903153157.png">查看图片：Pasted image 20250903153157.png</a></p><p>AST的生成过程是怎么样的呢？</p><p><strong>1. 词法分析（lexical analysis）</strong>：主要是将<strong>字符流（char stream）</strong> 转换成<strong>标记流（token stream）</strong>，字符流就是我们一行一行的代码，token是指语法上不能再分的、最小的单个字符或者字符串。</p><p><strong>2. 语法分析</strong>：将前面生成的token流根据语法规则，形成一个有元素层级嵌套的语法规则树，这个树就是AST。在此过程中，如果源代码不符合语法规则，则会终止，并抛出“语法错误”。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020250903153451.png">查看图片：Pasted image 20250903153451.png</a> Ignition执行上一步生成的字节码，并记录代码运行的次数等信息，如果同一段代码执行了很多次，就会被标记为 <strong>“HotSpot”（热点代码）</strong>，然后把这段代码发送给 <strong>编译器TurboFan</strong>，然后TurboFan把它编译为更高效的机器码储存起来，等到下次再执行到这段代码时，就会用现在的机器码替换原来的字节码进行执行，这样大大提升了代码的执行效率。<br> 另外，当TurboFan判断一段代码不再为热点代码的时候，会执行去优化的过程，把优化的机器码丢掉，然后执行过程回到Ignition。</p><h2 id="堆栈内存" tabindex="-1">堆栈内存 <a class="header-anchor" href="#堆栈内存" aria-label="Permalink to &quot;堆栈内存&quot;">​</a></h2><h3 id="栈内存ecs" tabindex="-1">栈内存ECS <a class="header-anchor" href="#栈内存ecs" aria-label="Permalink to &quot;栈内存ECS&quot;">​</a></h3><p>计算机开辟的<strong>内存空间</strong>用于执行JS代码，也叫执行环境栈。代码在执行前会自身形成一个执行上下文，会进入栈中执行。执行完的代码<strong>可能</strong>会出栈</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020250907202410.png">查看图片：Pasted image 20250907202410.png</a> 上述过程（简单数据类型）在内存中会：</p><ol><li>创建一个值为<code>10</code></li><li>创建一个变量<code>x</code></li><li>将变量和值关联在一起</li></ol><h3 id="变量对象-vo" tabindex="-1">变量对象（VO） <a class="header-anchor" href="#变量对象-vo" aria-label="Permalink to &quot;变量对象（VO）&quot;">​</a></h3><p>专门用来存储创建的值和变量。</p><ul><li>如果内存中存在已经创建过的变量，便不会再创建，会直接进行关联。</li><li>一个变量同一时间只能关联一个值，但一个值可以关联多个变量。</li></ul><h3 id="ecs-执行环境栈" tabindex="-1">ECS（执行环境栈） <a class="header-anchor" href="#ecs-执行环境栈" aria-label="Permalink to &quot;ECS（执行环境栈）&quot;">​</a></h3><p>用于管理执行上下文的栈结构，代码执行时会形成执行上下文并压入栈中，执行完毕后可能出栈。</p><h3 id="简单数据类型在内存中的处理" tabindex="-1">简单数据类型在内存中的处理 <a class="header-anchor" href="#简单数据类型在内存中的处理" aria-label="Permalink to &quot;简单数据类型在内存中的处理&quot;">​</a></h3><p>以<code>var x = 10</code>为例：</p><ol><li>首先进行声明动作（<code>var x</code>，也叫<code>declare</code>）。</li><li>然后进行定义/赋值动作（<code>x = 10</code>，也叫<code>defined</code>）。 在内存中会：</li><li>创建一个值为<code>10</code>。</li><li>创建一个变量<code>x</code>。</li><li>将变量和值关联在一起。 还有类似<code>var y; console.log(y); // undefined</code>的情况，变量<code>y</code>被声明但未赋值，所以打印<code>undefined</code>。</li></ol><h3 id="引用数据类型在内存中的处理" tabindex="-1">引用数据类型在内存中的处理 <a class="header-anchor" href="#引用数据类型在内存中的处理" aria-label="Permalink to &quot;引用数据类型在内存中的处理&quot;">​</a></h3><p>创建引用数据类型分三步：</p><ol><li>开辟一个==堆内存==，并自动生成一个16进制的地址。</li><li>将创建的复杂值（对象等）本身的属性放到堆中。</li><li>把这个16进制的地址交给变量（存在==栈==中）。 比如：</li></ol><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {n: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y.n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x.n); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 20</span></span></code></pre></div><p>这里<code>x</code>和<code>y</code>指向同一块堆内存地址，所以修改<code>y</code>的属性，<code>x</code>的属性也会改变。</p><h3 id="函数声明在内存中的声明" tabindex="-1">函数声明在内存中的声明 <a class="header-anchor" href="#函数声明在内存中的声明" aria-label="Permalink to &quot;函数声明在内存中的声明&quot;">​</a></h3><ol><li>函数是==引用==类型。</li><li>在堆中开辟空间后，其中存储函数相关内容，并以字符串的形式保存。</li><li>函数在创建时的执行上下文就被保存，内存中以<code>[Scope](Scope.md)</code>来存储其作用域等信息。</li><li>函数在执行时会形成全新的私有上下文并压入栈执行。</li></ol><h3 id="函数执行进栈后发生的事情" tabindex="-1">函数执行进栈后发生的事情 <a class="header-anchor" href="#函数执行进栈后发生的事情" aria-label="Permalink to &quot;函数执行进栈后发生的事情&quot;">​</a></h3><ol><li>初始化自身的作用域链（包含上级上下文等，和全局执行上下文的查找机制类似）。</li><li>初始化<code>this</code>指向：在全局函数调用中，<code>this</code>指向<code>window</code>（浏览器环境下）。</li><li>初始化形参集合：<code>arguments</code>（类数组，存储函数调用时的实参等）。</li><li>形参赋值：将实参的值赋给对应的形参。</li><li>变量提升：只有通过<code>var</code>声明的变量或者函数声明才会提升。变量提升是指变量的声明会被提升到当前作用域的顶部，但赋值不会提升；函数声明整体会被提升。</li><li>代码执行：按顺序执行函数内的代码。</li><li>执行完之后出栈：函数执行完毕，其执行上下文从执行环境栈中弹出，释放相关资源（当然，若有引用指向堆中的内容，堆内容不会立即释放）。</li></ol><h3 id="执行上下文execution-context" tabindex="-1">执行上下文Execution Context <a class="header-anchor" href="#执行上下文execution-context" aria-label="Permalink to &quot;执行上下文Execution Context&quot;">​</a></h3><ul><li>全局执行上下文（GEC）：window</li><li>函数执行上下文：每个函数有特有的环境，函数可以访问外面的变量（闭包）</li><li>块级执行上下文：在<code>{}</code>中的<code>let</code>与<code>const</code>无法在外面访问到，ES6提出</li></ul>`,32)])])}const g=e(n,[["render",o]]);export{k as __pageData,g as default};
